/**
 * Post-build script: patches the Clerk SDK chunk in the vinext build output
 * so that process.env has wrangler vars available at module load time.
 *
 * Cloudflare Workers only passes env vars via the fetch handler's `env` param,
 * but Clerk reads CLERK_SECRET_KEY at module load time. This script reads
 * wrangler.jsonc vars and injects them at the top of the Clerk chunk.
 */
import { readFileSync, writeFileSync, readdirSync } from "node:fs";
import { join } from "node:path";

const root = join(import.meta.dirname, "..");

// Read the built wrangler.json (valid JSON, generated by vinext build)
const wranglerConfig = JSON.parse(
  readFileSync(join(root, "dist", "server", "wrangler.json"), "utf-8")
);
const vars = wranglerConfig.vars || {};

const envLines = Object.entries(vars)
  .filter(([, v]) => typeof v === "string")
  .map(([k, v]) => `process.env[${JSON.stringify(k)}] ??= ${JSON.stringify(v)};`)
  .join(" ");

const injection = `globalThis.process ??= { env: {} }; globalThis.process.env ??= {}; ${envLines}\n`;

// Patch all keyless-node chunk files (where SECRET_KEY is defined)
const assetsDir = join(root, "dist", "server", "assets");
const files = readdirSync(assetsDir).filter(
  (f) => f.startsWith("keyless-node-") && f.endsWith(".js")
);

for (const file of files) {
  const filePath = join(assetsDir, file);
  let content = readFileSync(filePath, "utf-8");

  if (content.includes('process.env.CLERK_SECRET_KEY') && !content.startsWith("globalThis.process")) {
    writeFileSync(filePath, injection + content);
    console.log(`[patch-clerk-env] Patched ${file}`);
  } else {
    console.log(`[patch-clerk-env] ${file} already patched or no CLERK_SECRET_KEY reference`);
  }
}
